import { DialogWatcher } from "./utilities.types";

let watchers: DialogWatcher[] = [];

/**
 * Watch lifecycle events of a specified dialog managed by DialogManager
 */
function watchDialogLifecycle(
	id: string,
	callback: (event: string, args?: any) => undefined,
): undefined {
	watchers.push({ id, callback });
}

function emitEvent(id: string, event: string, args?: any) {
	watchers
		.filter((watcher) => watcher.id == id)
		.forEach((watcher) => watcher.callback(event, args));
}

function emitDialogClosed(id: string) {
	emitEvent(id, "closed");
}

function emitConfirmYes(id: string) {
	emitEvent(id, "yes");
}
function emitConfirmNo(id: string) {
	emitEvent(id, "no");
}

function emitPromptAnswered(id: string, answer: string) {
	emitEvent(id, "answered", answer);
}

export {
	watchDialogLifecycle,
	emitDialogClosed,
	emitConfirmYes,
	emitConfirmNo,
	emitPromptAnswered,
};
