import { Ref, VNode } from "vue";

interface AlertConfig {
	/**
	 * Body of the alert dialog
	 */
	content: string | VNode;
	/**
	 * Label of button for close the alert dialog
	 */
	buttonLabel?: string;
}

interface ConfirmConfig {
	/**
	 * Body of the alert dialog
	 */
	content: string | VNode;
	/**
	 * The label of "Yes" button
	 */
	yesLabel?: string;
	/**
	 * The label of "No" button
	 */
	noLabel?: string;
}

interface PromptConfig {
	/**
	 * Body of the alert dialog
	 */
	content: string | VNode;
	/**
	 * The label of the text input component
	 */
	inputLabel?: string;
	/**
	 * The placeholder of the text input component
	 */
	inputPlaceholder?: string;
	/**
	 * Temporary buffer of input
	 */
	_buffer: string;
}

enum DialogUtilityType {
	ALERT,
	CONFIRM,
	PROMPT,
}

type DialogUtilityConfig = (AlertConfig | ConfirmConfig | PromptConfig) & {
	id: string;
	type: DialogUtilityType;
	open: boolean;
};

interface DialogWatcher {
	/**
	 * The ID of dialog watching
	 */
	id: string;
	/**
	 * Callback function when event has been triggered
	 */
	callback: (event: string, args?: any) => undefined;
}

export {
	AlertConfig,
	ConfirmConfig,
	PromptConfig,
	DialogUtilityConfig,
	DialogUtilityType,
	DialogWatcher,
};
