<template>
	<div class="cdx-dialog-manager">
		<div class="cdx-dialog-manager--dialog-wrapper" v-for="dialog in store" :key="dialog.id">
			<CdxDialog
				v-if="dialog.type == DialogUtilityType.ALERT"
				title=""
				:open="dialog.open"
				:primary-action="{
					actionType: 'progressive',
					label: (dialog as AlertConfig).buttonLabel as string,
				}"
				@primary="() => onClosed(dialog.id)"
			>
				<component v-if="isVNode(dialog.content)" :is="dialog.content"></component>
				<span v-else-if="typeof dialog.content == 'string'">{{ dialog.content }}</span>
			</CdxDialog>
			<CdxDialog
				v-else-if="dialog.type == DialogUtilityType.CONFIRM"
				title=""
				:open="dialog.open"
				:primary-action="{
					actionType: 'progressive',
					label: (dialog as ConfirmConfig).yesLabel as string,
				}"
				:default-action="{ label: (dialog as ConfirmConfig).noLabel as string }"
				@primary="() => onConfirmYes(dialog.id)"
				@default="() => onConfirmNo(dialog.id)"
			>
				<component v-if="isVNode(dialog.content)" :is="dialog.content"></component>
				<span v-else-if="typeof dialog.content == 'string'">{{ dialog.content }}</span>
			</CdxDialog>
			<CdxDialog
				v-else-if="dialog.type == DialogUtilityType.PROMPT"
				title=""
				:open="dialog.open"
				:primary-action="{ actionType: 'progressive', label: 'OK' }"
				@primary="() => onPromptAnswered(dialog.id)"
			>
				<component v-if="isVNode(dialog.content)" :is="dialog.content"></component>
				<span v-else-if="typeof dialog.content == 'string'">{{ dialog.content }}</span>
				<CdxField>
					<template #label>
						<component
							v-if="isVNode((dialog as PromptConfig).inputLabel)"
							:is="(dialog as PromptConfig).inputLabel"
						></component>
						<span v-else-if="typeof (dialog as PromptConfig).inputLabel == 'string'">{{
							(dialog as PromptConfig).inputLabel
						}}</span>
					</template>
					<CdxTextInput
						v-model="(dialog as PromptConfig)._buffer"
						:placeholder="(dialog as PromptConfig).inputPlaceholder"
						@keydown.enter="() => onPromptAnswered(dialog.id)"
					></CdxTextInput>
				</CdxField>
			</CdxDialog>
		</div>
	</div>
</template>

<script setup lang="ts">
import { defineComponent, inject, isVNode } from "vue";
import { CdxDialog, CdxField, CdxTextInput } from "../../lib";
import {
	AlertConfig,
	ConfirmConfig,
	DialogUtilityConfig,
	DialogUtilityType,
	PromptConfig,
} from "./utilities.types";
import {
	emitConfirmNo,
	emitConfirmYes,
	emitDialogClosed,
	emitPromptAnswered,
} from "./dialog-watcher";

let store = inject("CdxDialogManager_Store") as DialogUtilityConfig[];

function onClosed(id: string) {
	emitDialogClosed(id);
	const dialog = store.find((dialog) => dialog.id == id);
	if (dialog) {
		dialog.open = false;
	}
}

function onConfirmYes(id: string) {
	emitConfirmYes(id);
	onClosed(id);
}
function onConfirmNo(id: string) {
	emitConfirmNo(id);
	onClosed(id);
}

function onPromptAnswered(id: string) {
	emitPromptAnswered(id, (store.find((dialog) => dialog.id == id) as PromptConfig)._buffer);
	onClosed(id);
}
</script>

<script lang="ts">
const CdxDialogManager = defineComponent({
	name: "CdxDialogManager",
	components: { CdxDialog, CdxField, CdxTextInput },
});

export default CdxDialogManager;
</script>
