import { provide, reactive, ref, VNode } from "vue";
import { DialogUtilityConfig, DialogUtilityType } from "./utilities.types";
import { useI18n } from "../../lib";
import { watchDialogLifecycle } from "./dialog-watcher";

let id = 0;

function genId() {
	return (id++).toString();
}

/**
 * Initialize and get operators of DialogManager
 */
function useDialogManager() {
	// This array stores dialogs created by utility functions
	let store: DialogUtilityConfig[] = reactive([]);

	provide("CdxDialogManager_Store", store);

	let defaultAlertButtonLabel = useI18n(
		"cdx-dialog-utility-alert-default-close-button-label",
		"Close",
	);

	let defaultConfirmYesLabel = useI18n(
		"cdx-dialog-utility-confirm-default-yes-button-label",
		"Yes",
	);
	let defaultConfirmNoLabel = useI18n("cdx-dialog-utility-confirm-default-no-button-label", "No");

	return {
		/**
		 * Shows a modal alert dialog with specified content and a single button to close
		 */
		alert(
			content: string | VNode,
			buttonLabel: string = defaultAlertButtonLabel.value,
		): Promise<undefined> {
			let id = genId();

			store.push({
				content,
				buttonLabel,
				id,
				type: DialogUtilityType.ALERT,
				open: true,
			});

			return new Promise(function (resolve) {
				watchDialogLifecycle(id, function () {
					resolve(undefined);
				});
			});
		},
		/**
		 * Ask users yes or no by shows a modal confirm dialog with specified content and two option buttons.
		 */
		confirm(
			content: string | VNode,
			yesLabel: string = defaultConfirmYesLabel.value,
			noLabel: string = defaultConfirmNoLabel.value,
		): Promise<undefined> {
			let id = genId();

			store.push({
				content,
				yesLabel,
				noLabel,
				id,
				type: DialogUtilityType.CONFIRM,
				open: true,
			});

			return new Promise(function (resolve, reject) {
				watchDialogLifecycle(id, function (event) {
					if (event == "yes") resolve(undefined);
					else if (event == "no") reject(undefined);
				});
			});
		},
		/**
		 * Ask a question from user by shows a modal prompt dialog with specified content and an input box
		 */
		prompt(
			content: string | VNode,
			inputLabel: string = "",
			inputPlaceholder: string = "",
		): Promise<string> {
			let id = genId();

			store.push({
				content,
				inputLabel,
				inputPlaceholder,
				_buffer: "",
				id,
				type: DialogUtilityType.PROMPT,
				open: true,
			});

			return new Promise(function (resolve) {
				watchDialogLifecycle(id, function (event, arg) {
					if (event == "answered") resolve(arg as string);
				});
			});
		},
	};
}

export default useDialogManager;
